def decode_and_verify_token(token):
    """
    Decode and VERIFY a JWT token securely.

    Supports both symmetric (HS256) and asymmetric (RS256) algorithms.
    Always verifies signature, expiration, issuer, and audience.
    """
    algorithm = CONFIG["JWT_ALGORITHM"]

    decode_options = {
        "verify_signature": True,  # ALWAYS verify signature
        "verify_exp": True,        # ALWAYS verify expiration
        "verify_iat": True,        # Verify issued-at
        "verify_nbf": True,        # Verify not-before
        "require": ["exp", "iat", "sub"],  # Require essential claims
    }

    decode_kwargs = {
        "algorithms": [algorithm],  # Explicitly whitelist allowed algorithms
        "options": decode_options,
    }

    # Set up the verification key based on algorithm type
    if algorithm.startswith("RS") or algorithm.startswith("ES"):
        # Asymmetric algorithm - use public key from JWKS
        if not jwks_client:
            raise jwt.InvalidTokenError("JWKS URL not configured for asymmetric verification")
        key = jwks_client.get_signing_key(token)
    elif algorithm.startswith("HS"):
        # Symmetric algorithm - use shared secret
        key = CONFIG["JWT_SECRET"]
        if not key:
            raise jwt.InvalidTokenError("JWT_SECRET not configured")
    else:
        raise jwt.InvalidTokenError(f"Unsupported algorithm: {algorithm}")

    # Add issuer verification if configured
    if CONFIG["JWT_ISSUER"]:
        decode_kwargs["issuer"] = CONFIG["JWT_ISSUER"]

    # Add audience verification if configured
    if CONFIG["JWT_AUDIENCE"]:
        decode_kwargs["audience"] = CONFIG["JWT_AUDIENCE"]

    return jwt.decode(token, key, **decode_kwargs)


def extract_token_from_header():
    """Extract Bearer token from Authorization header."""
    auth_header = request.headers.get("Authorization")

    if not auth_header:
        return None

    parts = auth_header.split()

    if len(parts) != 2 or parts[0].lower() != "bearer":
        return None

    return parts[1]


def require_auth(f):
    """Decorator that enforces JWT authentication on a route."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = extract_token_from_header()

        if not token:
            logger.warning(
                "Missing or malformed Authorization header from %s",
                request.remote_addr,
            )
            return jsonify({
                "error": "unauthorized",
                "message": "Missing or malformed Authorization header. Expected: Bearer <token>",
            }), 401

        try:
            claims = decode_and_verify_token(token)
        except jwt.ExpiredSignatureError:
            logger.warning("Expired token from %s", request.remote_addr)
            return jsonify({
                "error": "token_expired",
                "message": "Token has expired. Please obtain a new token.",
            }), 401
        except jwt.InvalidIssuerError:
            logger.warning("Invalid issuer in token from %s", request.remote_addr)
            return jsonify({
                "error": "invalid_token",
                "message": "Token issuer is not trusted.",
            }), 401
        except jwt.InvalidAudienceError:
            logger.warning("Invalid audience in token from %s", request.remote_addr)
            return jsonify({
                "error": "invalid_token",
                "message": "Token audience mismatch.",
            }), 401
        except jwt.InvalidTokenError as e:
            logger.warning(
                "Invalid token from %s: %s", request.remote_addr, str(e)
            )
            return jsonify({
                "error": "invalid_token",
                "message": "Token validation failed.",
            }), 401

        # Store validated claims in Flask's request context
        g.user_claims = claims
        g.user_id = claims.get("sub")
        g.user_roles = claims.get("roles", [])
        g.raw_token = token

        return f(*args, **kwargs)

    return decorated


def require_role(required_role):
    """Decorator that checks if the authenticated user has a specific role."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not hasattr(g, "user_roles") or required_role not in g.user_roles:
                logger.warning(
                    "User %s attempted to access resource requiring role '%s'",
                    getattr(g, "user_id", "unknown"),
                    required_role,
                )
                return jsonify({
                    "error": "forbidden",
                    "message": f"Insufficient permissions. Required role: {required_role}",
                }), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


def forward_to_backend(method, path, **kwargs):
    """Forward a request to the backend service with user claims as headers."""
    backend_url = f"{CONFIG['BACKEND_BASE_URL']}{path}"

    # Build headers to forward user identity to backend services
    forward_headers = {
        "X-User-Id": str(g.user_id) if g.user_id else "",
        "X-User-Roles": ",".join(g.user_roles) if g.user_roles else "",
        "X-User-Claims": jwt.encode(g.user_claims, "internal-only", algorithm="HS256"),
        "Content-Type": request.content_type or "application/json",
        # Forward original Authorization for services that need it
        "Authorization": request.headers.get("Authorization", ""),
    }

    # Copy select safe headers from the original request
    for header in ["Accept", "Accept-Language", "X-Request-Id"]:
        if header in request.headers:
            forward_headers[header] = request.headers[header]

    try:
        response = requests.request(
            method=method,
            url=backend_url,
            headers=forward_headers,
            params=request.args,
            data=request.get_data(),
            timeout=30,
        )

        # Build response, excluding hop-by-hop headers
        excluded_headers = {
            "content-encoding", "content-length", "transfer-encoding", "connection"
        }
        response_headers = {
            k: v for k, v in response.headers.items()
            if k.lower() not in excluded_headers
        }

        return (response.content, response.status_code, response_headers)

    except requests.Timeout:
        logger.error("Backend request timed out: %s %s", method, backend_url)
        return jsonify({"error": "gateway_timeout", "message": "Backend service timed out"}), 504
    except requests.ConnectionError:
        logger.error("Backend connection failed: %s %s", method, backend_url)
        return jsonify({"error": "bad_gateway", "message": "Backend service unavailable"}), 502
    except requests.RequestException as e:
        logger.error("Backend request failed: %s %s - %s", method, backend_url, str(e))
        return jsonify({"error": "bad_gateway", "message": "Backend request failed"}), 502


